@@ -474,25 +478,32 @@ select {
   margin-left: auto;
 }

-.pickerList {
+.pickerPositioner {
   position: absolute;
   z-index: 20;
   top: calc(100% + 6px);
   left: 0;
   right: 0;
+  min-width: 100%;
+}
+
+.pickerContent {
   background: color-mix(in srgb, var(--panel) 88%, transparent);
   border: 1px solid var(--border);
   border-radius: 14px;
   padding: 6px;
   box-shadow: 0 12px 24px rgba(0, 0, 0, 0.2);
   backdrop-filter: blur(14px);
   -webkit-backdrop-filter: blur(14px);
+}
+
+.pickerContent[hidden] {
   display: none;
-  gap: 4px;
 }

-.picker[data-open="true"] .pickerList {
+.pickerList {
   display: grid;
+  gap: 4px;
 }

 .pickerOption {
